import json, ssl, urllib.request
from html.parser import HTMLParser

def get_og_image(url):
    """Fetch og:image from URL."""
    try:
        ctx = ssl.create_default_context()
        ctx.load_verify_locations("/usr/local/lib/python3.14/site-packages/certifi/cacert.pem")
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        with urllib.request.urlopen(req, timeout=10, context=ctx) as r:
            html = r.read(32000).decode("utf-8", errors="ignore")
        # simple regex-free parse
        for tag in ["og:image", "twitter:image"]:
            marker = f'property="{tag}"'
            idx = html.find(marker)
            if idx == -1:
                marker = f"property='{tag}'"
                idx = html.find(marker)
            if idx == -1:
                marker = f'name="{tag}"'
                idx = html.find(marker)
            if idx != -1:
                # find content= nearby
                snippet = html[max(0,idx-200):idx+200]
                for q in ['"', "'"]:
                    ci = snippet.find(f"content={q}")
                    if ci != -1:
                        start = ci + len(f"content={q}")
                        end = snippet.find(q, start)
                        if end != -1:
                            return snippet[start:end]
    except Exception:
        pass
    return ""

